def latency_time():
    start = time.time()
    def decorator(f):
        def decorated_function(*args, **kwargs):
            result = f(*args, **kwargs)
            LATENCY_HISTOGRAM.observe(time.time() - start)
            return result
        return decorated_function
    return decorator

